INSERT INTO `products` (`id`, `name`, `price`, `description`, `imageUrl`) VALUES
(1, 'Краски акриловые', '250 ₽', 'Яркие акриловые краски для рисования на различных поверхностях.', 'http://localhost:5000/uploads/products/opt_6348b303-4487-4997-8e9a-cfe79d6c5e5a.jpg'),
(2, 'Кисти для рисования', '350 ₽', 'Набор кистей различных размеров для акриловых и масляных красок.', 'https://avatars.mds.yandex.net/i?id=0bd360cb224af7012c8e45d61e9b9faf_l-5896582-images-thumbs&n=13'),
(3, 'Бумага для акварели', '1000 ₽', 'Специальная бумага для акварели и акрила.', 'https://avatars.mds.yandex.net/get-mpic/7052428/img_id3989026280302142340.jpeg/orig'),
(4, 'Масляные краски', '1400 ₽', 'Качественные масляные краски для художников.', 'https://cdn.peredvizhnik.ru/upload/iblock/02f/nabor_maslyanykh_krasok_sonet_12tsv_po_10ml_v_kartonnoy_upakovke.jpg?1582619035274158'),
(5, 'Эскизный блокнот', '600 ₽', 'Блокнот с белыми страницами для зарисовок и идей.', 'https://i.ebayimg.com/images/g/ZcMAAOSwQRhe~1F~/s-l1600.jpg'),
(6, 'Палитра для смешивания', '800 ₽', 'Палитра для удобного смешивания красок.', 'https://fb.ru/misc/i/gallery/78264/2758304.jpg'),
(7, 'Гуашь', '1200 ₽', 'Набор гуашевых красок для ярких и насыщенных картин.', 'https://fkniga.ru/media/product/06/06030204/KA-00101221_03.jpg'),
(8, 'Цветные карандаши', '400 ₽', 'Набор цветных карандашей для рисования и творчества.', 'https://avatars.mds.yandex.net/i?id=e6d5500bd0c822fe852a4914f261fe50_l-4570529-images-thumbs&n=13'),
(9, 'Фломастеры', '500 ₽', 'Набор фломастеров с яркими цветами для творчества.', 'https://cdn1.ozone.ru/s3/multimedia-l/6248236221.jpg'),
(10, 'Мелки цветные', '300 ₽', 'Набор цветных мелков для рисования и творчества.', 'https://i.pinimg.com/originals/b6/af/58/b6af586874dfe9f8ab574c7f07f1a77c.jpg'),
(11, 'Набор штампов для творчества', '950 ₽', 'Деревянные штампы с растительными и геометрическими узорами для отпечатков на бумаге и ткани.', 'https://avatars.mds.yandex.net/get-mpic/15300889/2a000001969b6ec50dc8e6314a875273c224/orig'),
(12, 'Глиняная масса для лепки', '750 ₽', 'Полимерная глина для лепки фигурок и украшений, затвердевает на воздухе.', 'https://example.com/images/clay.jpg'),
(13, 'Набор для эпоксидной смолы', '2100 ₽', 'Всё для создания украшений и арт-объектов: смола, формы, пигменты, перчатки.', 'https://basket-05.wbbasket.ru/vol964/part96401/96401502/images/big/1.webp'),
(14, 'Мольберт настольный', '1850 ₽', 'Компактный деревянный мольберт для рисования дома или в студии.', 'http://localhost:5000/uploads/products/opt_977f3143-6325-4e69-86e5-b9d9152a9d64.jpg'),
(15, 'Скетчбук с тонированной бумагой', '890 ₽', 'Бумага оттенка крафт, отлично подходит для линеров, маркеров и пастели.', 'https://example.com/images/sketchbook.jpg'),
(16, 'Линеры для скетчинга', '540 ₽', 'Набор чёрных линеров с разной толщиной наконечника (0.1–0.8 мм), водостойкие.', 'https://example.com/images/liners.jpg'),
(17, 'Набор блёсток и потали', '430 ₽', 'Золотая и серебряная поталь, блёстки, клей для декорирования открыток и картин.', 'https://example.com/images/glitter.jpg'),
(18, 'Каллиграфический набор', '1670 ₽', 'Перьевая ручка, сменные насадки, тушь и пропись для начинающих каллиграфов.', 'https://example.com/images/calligraphy.jpg'),
(19, 'Пастель масляная', '820 ₽', 'Набор 24 цветов, мягкая и яркая, легко смешивается и растушёвывается.', 'https://example.com/images/oilpastel.jpg'),
(20, 'Доска для лепки и резки', '390 ₽', 'Силиконовый коврик с разметкой, не прилипает к глине и легко моется.', 'https://example.com/images/mat.jpg'),
(21, 'Акриловые краски', '700 ₽', 'Набор 12 цветов по 20 мл, яркие и укрывистые.', 'https://example.com/acrylic.jpg'),
(22, 'Кисти синтетика набор 5 шт', '450 ₽', 'Размеры 2,4,6,8,10 для акрила и гуаши.', 'https://example.com/brushes.jpg'),
(23, 'Бумага для акварели А4', '350 ₽', '200 г/м², 20 листов, гладкая и зернистая.', 'https://example.com/watercolor_paper.jpg'),
(24, 'Гуашь художественная', '580 ₽', 'Набор 16 цветов, матовая и плотная.', 'https://example.com/gouache.jpg'),
(25, 'Цветные карандаши', '620 ₽', '24 цвета, мягкий грифель, трёхгранная форма.', 'https://example.com/colored_pencils.jpg'),
(27, 'Пластилин для лепки', '320 ₽', '10 цветов, мягкий, не липнет к рукам.', 'https://example.com/plasticine.jpg'),
(28, 'Набор фломастеров', '410 ₽', '18 цветов, на водной основе, смываются с рук.', 'https://example.com/markers.jpg'),
(29, 'Альбом для рисования А4', '280 ₽', '20 листов, плотная бумага 160 г/м², скоба.', 'https://example.com/album.jpg'),
(30, 'Скетчбук А5', '390 ₽', '60 листов, бумага 120 г/м², твёрдая обложка.', 'https://example.com/sketchbook.jpg'),
(31, 'Акварель медовая', '890 ₽', 'Набор 24 цвета, прозрачные, яркие оттенки.', 'https://example.com/watercolor.jpg'),
(32, 'Холст на подрамнике 30x40 см', '550 ₽', 'Хлопок, грунтованный, готов к работе.', 'https://example.com/canvas.jpg'),
(33, 'Мольберт тренога', '3200 ₽', 'Буковый, регулируемый, до 120 см.', 'https://example.com/easel.jpg'),
(34, 'Палитра деревянная', '460 ₽', 'Овальная, с отверстием для пальца.', 'https://example.com/palette.jpg'),
(35, 'Линеры чёрные набор 6 шт', '520 ₽', 'Толщина 0.05–0.8 мм, водостойкие.', 'https://example.com/liners.jpg'),
(36, 'Каллиграфический набор', '1450 ₽', 'Перьевая ручка, 5 насадок, тушь 30 мл.', 'https://example.com/calligraphy.jpg'),
(37, 'Набор штампов и подушек', '780 ₽', '8 штампов, 4 цвета подушек.', 'https://example.com/stamps.jpg'),
(38, 'Доска для лепки А3', '390 ₽', 'Силиконовая, складная, с разметкой.', 'https://example.com/clay_board.jpg'),
(39, 'Полимерная глина', '640 ₽', '6 цветов по 50 г, запекаемая.', 'https://example.com/polymer_clay.jpg'),
(40, 'Набор дотсов для точек', '370 ₽', '10 шт разного диаметра для точечной росписи.', 'https://example.com/dots.jpg'),
(41, 'Эпоксидная смола', '2100 ₽', 'Комплект 1 кг + отвердитель, для украшений и заливок.', 'https://example.com/epoxy.jpg'),
(42, 'Набор пигментов для смолы', '890 ₽', '10 цветов, концентрированные.', 'https://example.com/pigments.jpg'),
(43, 'Скрапбукинг набор', '1560 ₽', 'Бумага 20 листов, наклейки, вырубка, ленты.', 'https://example.com/scrapbooking.jpg'),
(44, 'Набор для валяния (фелтинг)', '980 ₽', 'Шерсть 10 цветов, иглы, губка.', 'https://example.com/felting.jpg'),
(46, 'Машинка для вырубки', '5200 ₽', 'Ручная, с набором металлических трафаретов.', 'https://example.com/die_cutting.jpg'),
(47, 'Термопистолет с блёстками', '1250 ₽', 'Расплавляет блёстки для объёмных рисунков.', 'https://example.com/glitter_gun.jpg'),
(48, 'Набор трафаретов', '490 ₽', '20 штук: растения, буквы, абстракция.', 'https://example.com/stencils.jpg'),
(49, 'Коврик для резки самовосстанавливающийся', '1150 ₽', 'Формат А2, с разметкой.', 'https://example.com/cutting_mat.jpg'),
(50, 'Спрей акварельный', '680 ₽', '3 цвета, создаёт эффект размытия.', 'https://example.com/spray.jpg'),
(51, 'Набор для рисования светом', '2300 ₽', 'Световое перо, трафареты, затемнённая плёнка.', 'https://example.com/light_drawing.jpg'),
(52, 'Каллиграфический маркер-кисть', '310 ₽', 'Двусторонний: кисть и тонкий наконечник.', 'https://example.com/brush_pen.jpg'),
(53, 'Набор жидкого акрила (пор-арт)', '1950 ₽', '6 цветов, разбавитель, инструкция.', 'https://example.com/pour_acrylic.jpg'),
(54, 'Маска для рисования (маскировочная жидкость)', '270 ₽', '50 мл, защищает участки бумаги.', 'https://example.com/masking_fluid.jpg'),
(55, 'Гель с глиттером объёмный', '380 ₽', '3D эффект, 4 цвета.', 'https://example.com/3d_glitter.jpg'),
(56, 'Набор фактурных паст', '870 ₽', 'Паста каменная, песчаная, жемчужная.', 'https://example.com/texture_paste.jpg'),
(57, 'Трафареты для шебби-шик', '540 ₽', 'Винтажные узоры, цветы, кружево.', 'https://example.com/shabby_stencils.jpg'),
(58, 'Скетчбук с чёрной бумагой', '710 ₽', 'Листы 140 г/м², для белых ручек и пастели.', 'https://example.com/black_paper.jpg'),
(59, 'Набор неоновых красок', '990 ₽', '8 цветов, светятся в УФ-свете.', 'https://example.com/neon_paint.jpg'),
(60, 'Пенал-органайзер для кистей', '450 ₽', 'На 24 кисти, скручивается в рулон.', 'https://example.com/brush_roll.jpg'),
(71, 'Тетрадь в клетку (48 л.)', '120 ₽', 'Тетрадь розовая, скрепка, 48 листов, в клетку.', 'http://localhost:5000/uploads/products/opt_a032b33b-5ceb-4e3c-b678-f2cc80484c8d.jpg'),
(73, 'Набор \"Студент-старт\" (10 предметов)', '990 ₽', 'Состав набора: Тетрадь 48л клетка (2 шт), Тетрадь 48л линейка (2 шт), Ручка синяя (2 шт), Карандаш простой (2 шт), Ластик, Точилка. Все необходимое для начала семестра в одной коробке.', 'https://example.com/student_start_set.jpg'),
(74, 'Набор \"Сессия под контролем\" (7 предметов)', '750 ₽', 'Состав набора: Тетрадь 96л клетка, Тетрадь 48л линейка, Ручки черные (2 шт), Маркеры-текстайзеры (2 цвета), Стикеры для заметок.', 'https://example.com/session_set.jpg'),
(75, 'Набор \"Экзамен близко\" (5 предметов)', '550 ₽', 'Состав набора: Тетрадь 96л клетка, Блокнот А5 80л, Ручка синяя, Карандаш механический, Стирательная резинка.', 'https://example.com/exam_set.jpg'),
(76, 'Тетрадь 12л клетка, обложка мелованная', '15 ₽', '12 листов в клетку. Бумага 65 г/м. Самый бюджетный вариант для черновиков.', 'https://example.com/notebook_12l.jpg'),
(77, 'Тетрадь 12л линейка, обложка мелованная', '15 ₽', '12 листов в линейку. Бумага 65 г/м.', 'https://example.com/notebook_12l_line.jpg'),
(78, 'Ручка шариковая синяя \"Эконом\"', '12 ₽', 'Прозрачный корпус. Синие чернила. Толщина линии 0.7 мм. Простая надежная ручка для повседневного письма.', 'https://example.com/pen_cheap.jpg'),
(79, 'Карандаш простой HB, заточенный', '8 ₽', 'Классический черный карандаш. Твердость HB (мягко-твердый).', 'https://example.com/pencil_hb.jpg'),
(80, 'Ластик \"Студент\" белый', '12 ₽', 'Мягкий ластик, не мажет бумагу. Стирает карандаш без разводов.', 'https://example.com/eraser_white.jpg'),
(81, 'Точилка пластиковая с контейнером', '18 ₽', 'Пластиковая точилка с прозрачным контейнером для стружки. Подходит для стандартных карандашей.', 'https://example.com/sharpener.jpg'),
(82, 'Тетрадь общая 96л, клетка, А5', '189 ₽', 'Тип: Тетрадь общая. Формат: А5 (148x210 мм). Количество листов: 96. Линовка: Клетка. Бумага: Офсет, 70 г/м, белая. Обложка: Твердая, картон 7БЦ. Скрепление: Сшивка. Особенности: Закругленные углы, поля для заметок.', 'https://example.com/notebook_96l_detail.jpg'),
(83, 'Блокнот А5, 40л, точка, спираль', '129 ₽', 'Тип: Блокнот. Формат: А5 (148x210 мм). Количество листов: 40. Линовка: Точка (dot grid) - идеально для скетчноутинга и планирования. Бумага: Офсет, 80 г/м, кремовая. Обложка: Ламинированный картон. Скрепление: Спираль (металлическая). Особенности: Отрывные страницы, кармашек на обложке.', 'https://example.com/notebook_dot_grid.jpg'),
(84, 'Корректор-роллер \"Стиль\" 5м х 5мм', '85 ₽', 'Тип: Роллер (ленточный корректор). Длина ленты: 5 метров. Ширина ленты: 5 мм. Цвет корпуса: Белый. Особенности: Скрытый механизм, блокировка от перематывания.', 'https://example.com/correction_tape.jpg'),
(85, 'Бумага А4 500л, \"Снегурочка\"', '399 ₽', 'Характеристики: Формат А4 (210x297 мм). Плотность: 80 г/м. Белизна: 146% CIE. Класс: С. Оптовые цены: 1 пачка - 399 руб, 5 пачек - 380 руб/шт, 10 пачек - 360 руб/шт. Идеально для принтеров, копиров и факсов.', 'https://example.com/paper_a4_500.jpg'),
(86, 'Картридж HP 122XL черный', '2150 ₽', 'Оригинальный картридж HP 122XL. Ресурс: 300 страниц. Совместимость: HP Deskjet серии 2100, 2300. Тип: Черный. Технология: Термоструйная печать. Оптовые цены: 1 шт - 2150 руб, 3 шт - 2050 руб/шт, 5 шт - 1950 руб/шт.', 'https://example.com/cartridge_hp_122xl.jpg'),
(87, 'Стикеры самоклеящиеся 76x76 мм, 100л', '350 ₽', 'Классические желтые стикеры. Размер: 76x76 мм. Количество листов: 100. Клейкие заметки для офиса. Оптовые цены: 1 блок - 350 руб, 5 блоков - 320 руб/шт, 10 блоков - 290 руб/шт.', 'https://example.com/sticky_notes.jpg'),
(88, 'Папка-регистратор 75мм, картон, А4', '180 ₽', 'Папка-регистратор с кольцевым механизмом. Ширина корешка: 75 мм. Материал: Ламинированный картон. Формат: А4. Цвет: Синий. Вмещает до 500 листов.', 'https://example.com/binder_75mm.jpg'),
(89, 'Салфетки для оргтехники, 100шт', '250 ₽', 'Специальные салфетки для чистки принтеров, сканеров и копировальных аппаратов. Не оставляют ворса. Упаковка: 100 штук. Оптовые цены: 1 упаковка - 250 руб, 3 упаковки - 220 руб/шт.', 'https://example.com/printer_wipes.jpg'),
(90, 'Ручка шариковая синяя Erich Krause, 0.7мм', '35 ₽', 'Офисная ручка Erich Krause. Синие чернила. Толщина линии: 0.7 мм. Прозрачный корпус. Колпачок с клипом.', 'https://example.com/pen_erich_krause.jpg'),
(91, 'Маркер для досок черный, 2мм', '65 ₽', 'Маркер для белых досок. Цвет: черный. Скошенный наконечник 2 мм. Стирается сухой губкой. Защита от высыхания до 7 дней.', 'https://example.com/marker_whiteboard_black.jpg'),
(92, 'Степлер №24/6, 10 листов', '280 ₽', 'Офисный степлер. Тип скоб: №24/6. Мощность: до 10 листов. Металлический механизм. Цвет: черный.', 'https://example.com/stapler_10_sheets.jpg'),
(93, 'Пластилин \"Безопасное творчество\", 8 цветов', '320 ₽', 'Мягкий пластилин на растительной основе. Пометки: ГИПОАЛЛЕРГЕННО, НЕТОКСИЧНО. Без запаха. Не красит руки. Подходит для детей от 3 лет. В наборе: 8 цветов по 30 г.', 'https://example.com/safe_plasticine.jpg'),
